import React, { useState } from "react";
import axios from "axios";
import "bootstrap/dist/css/bootstrap.min.css";

// URL dinámica para producción (Render) o local
const API_URL = process.env.REACT_APP_API_URL || "http://localhost:5000";

export default function Login() {
  const [correo, setCorreo] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");
    setLoading(true);

    try {
      // Nota: Cambiamos a la ruta que definiste en tu index.js
      const res = await axios.post(`${API_URL}/api/usuarios/login`, {
        correo,
        password,
      });

      // ✅ El backend de Postgres devuelve result.rows[0] mapeado como 'usuario'
      if (res.data.usuario) {
        const { id, rol, nombre } = res.data.usuario;
        
        // Guardamos en localStorage para persistencia básica
        localStorage.setItem("usuarioId", id);
        localStorage.setItem("rol", rol);
        localStorage.setItem("nombre", nombre);

        // Redirigir al dashboard
        window.location.href = "/Dashboard";
      }
    } catch (err) {
      console.error("❌ Error en login:", err.response?.data || err.message);
      setError(err.response?.data?.message || "Correo o contraseña incorrectos");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="container d-flex align-items-center justify-content-center vh-100 bg-light">
      <div className="card shadow-lg border-0 p-4" style={{ maxWidth: "400px", width: "100%", borderRadius: "15px" }}>
        <div className="text-center mb-4">
          <h2 className="fw-bold text-primary">Bienvenido</h2>
          <p className="text-muted">Ingresa tus credenciales para continuar</p>
        </div>

        {error && <div className="alert alert-danger text-center py-2">{error}</div>}

        <form onSubmit={handleSubmit}>
          <div className="mb-3">
            <label className="form-label fw-bold">Correo Electrónico</label>
            <input
              type="email"
              className="form-control form-control-lg"
              placeholder="ejemplo@correo.com"
              value={correo}
              onChange={(e) => setCorreo(e.target.value)}
              required
            />
          </div>

          <div className="mb-4">
            <label className="form-label fw-bold">Contraseña</label>
            <input
              type="password"
              className="form-control form-control-lg"
              placeholder="••••••••"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
            />
          </div>

          <button 
            type="submit" 
            className="btn btn-primary btn-lg w-100 shadow-sm" 
            disabled={loading}
          >
            {loading ? (
              <span className="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span>
            ) : (
              "Entrar al Sistema"
            )}
          </button>
        </form>

        <div className="mt-4 p-3 bg-light rounded text-center" style={{ fontSize: "0.85rem" }}>
          <span className="text-muted">Credenciales de prueba:</span><br/>
          <strong>admin@correo.com</strong> / <strong>Alexander2002@poolo</strong>
        </div>
      </div>
    </div>
  );
}
